  ('social-worker-moex-02157', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於單案設計（single-case design）的說法，下列敘述何者錯誤？', '["單案設計是種應用時間序列設計邏輯，評估方案實務效果的評估方式", "單案設計主要思維在於比較方案介入前與方案介入後資料的比較", "當案主處於危機狀況時，無法獲得介入前資料，使用單案設計從事因果關係解釋則有限制", "單案設計常被人質疑內在效度不佳"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "88073911b247", "answer_pdf_sha1": "449337010204", "source_family": "moex-gov-tw", "moex": {"exam_code": "106030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
